"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import { AnimatePresence, motion } from "framer-motion";
import {
  Archive, ArrowRight, CalendarDays, Camera, Check, CheckCircle2, ChevronRight, ClipboardList,
  Cloud, Copy, Download, Eye, EyeOff, File, Film, Folder, HardDrive, KeyRound, LayoutDashboard,
  Loader2, LockKeyhole, LogOut, Menu, Play, Plus, RefreshCw, Search, Sparkles, Trash2, Upload,
  UsersRound, WandSparkles, X
} from "lucide-react";
import { useAppStore } from "@/lib/useAppStore";
import { contentCategories, people, serviceStatuses, videoStatuses } from "@/lib/appData";

const folderMime = "application/vnd.google-apps.folder";
const nav = [
  ["home", "Home", LayoutDashboard], ["services", "Services", CalendarDays], ["videos", "Videos", Film],
  ["calendar", "Calendar", CalendarDays], ["checklists", "Checklists", ClipboardList], ["files", "Files", HardDrive],
  ["gear", "Gear", Camera], ["access", "Access", KeyRound], ["people", "People", UsersRound]
];

const cx = (...v) => v.filter(Boolean).join(" ");
const uid = (p="item") => `${p}-${Date.now()}-${Math.random().toString(36).slice(2,8)}`;
const todayInput = () => new Date().toISOString().slice(0,10);
const prettyDate = (d) => d ? new Date(`${d}T12:00:00`).toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric" }) : "No date";

function getTimeContext(data) {
  const now = new Date();
  const day = now.toLocaleDateString("en-US", { weekday: "long" });
  const hour = now.getHours() + now.getMinutes() / 60;
  const date = todayInput();
  const windows = [
    { templateId: "sunday-am", day: "Sunday", label: "Sunday Morning", start: 7.5, end: 13.5 },
    { templateId: "sunday-pm", day: "Sunday", label: "Sunday Evening", start: 15.5, end: 21.25 },
    { templateId: "wednesday", day: "Wednesday", label: "Wednesday Night", start: 15.5, end: 22 }
  ];
  const window = windows.find((w) => w.day === day && hour >= w.start && hour <= w.end);
  if (window) {
    const service = data.services.find((s) => s.date === date && s.templateId === window.templateId);
    return {
      mode: "service",
      title: service ? `${window.label} is ready` : `Create ${window.label}`,
      body: service ? "This service already exists. Open it to upload videos, finish the checklist, and update statuses." : "This is the right service window. Create it now so folders, videos, and the checklist are ready.",
      templateId: window.templateId,
      service
    };
  }
  const due = data.videos.filter((v) => ["Needs upload", "Needs edit", "Ready to post"].includes(v.status));
  return { mode: "normal", title: "Keep the media flow moving", body: due.length ? "Videos need upload, editing, or posting attention." : "No urgent service window right now. Review videos, upcoming posts, gear, or create a custom service.", due };
}

function Card({ children, className="" }) { return <div className={cx("glass rounded-[1.7rem] p-5", className)}>{children}</div>; }
function Soft({ children, className="" }) { return <div className={cx("soft rounded-[1.35rem] p-4", className)}>{children}</div>; }
function Pill({ children, tone="default" }) {
  const t = { default:"bg-white/10 text-white/70", sky:"bg-sky-400/14 text-sky-100", green:"bg-emerald-400/14 text-emerald-100", orange:"bg-orange-400/14 text-orange-100", red:"bg-red-400/14 text-red-100", violet:"bg-violet-400/14 text-violet-100" };
  return <span className={cx("rounded-full px-3 py-1 text-xs", t[tone] || t.default)}>{children}</span>;
}
function Section({ eyebrow, title, action }) { return <div className="mb-4 flex items-end justify-between gap-4"><div>{eyebrow && <p className="text-xs uppercase tracking-[0.25em] text-sky-100/45">{eyebrow}</p>}<h2 className="mt-1 text-xl font-semibold tracking-tight sm:text-2xl">{title}</h2></div>{action}</div>; }
function Empty({ icon: Icon, title, body, action }) { return <div className="rounded-[1.6rem] border border-dashed border-white/14 bg-white/[0.03] p-10 text-center"><Icon className="mx-auto text-white/28" size={40}/><h3 className="mt-4 text-lg font-semibold">{title}</h3><p className="mx-auto mt-2 max-w-md text-sm leading-6 text-white/45">{body}</p>{action && <div className="mt-5">{action}</div>}</div>; }

export default function DashboardPage() {
  const [currentUser, setCurrentUser] = useState(null);
  const { data, setData, resetData, loading, source, saveState } = useAppStore(currentUser);
  const [active, setActive] = useState("home");
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [modal, setModal] = useState(null);
  const [toast, setToast] = useState(null);
  const [files, setFiles] = useState([]);
  const [folderId, setFolderId] = useState("root");
  const [folderStack, setFolderStack] = useState([{ id: "root", name: "My Drive" }]);
  const [fileSearch, setFileSearch] = useState("");
  const [driveLoading, setDriveLoading] = useState(false);
  const [driveError, setDriveError] = useState("");
  const uploadRef = useRef(null);

  useEffect(() => { (async () => { try { const res = await fetch("/api/session"); const body = await res.json(); if (!res.ok || !body.authorized) return (window.location.href = "/"); setCurrentUser(body.user); } catch { window.location.href = "/"; } })(); }, []);
  useEffect(() => { if (currentUser) loadFiles("root"); }, [currentUser]);

  const isAdmin = currentUser?.role === "admin";
  const timeContext = useMemo(() => getTimeContext(data), [data]);
  const videosByService = useMemo(() => data.videos.reduce((a, v) => ({ ...a, [v.serviceId || "none"]: [...(a[v.serviceId || "none"] || []), v] }), {}), [data.videos]);
  const driveFolders = files.filter((f) => f.mimeType === folderMime);
  const driveFiles = files.filter((f) => f.mimeType !== folderMime);

  function showToast(kind, title, body) { setToast({ kind, title, body, id: Date.now() }); setTimeout(() => setToast(null), 4200); }
  async function apiJson(res) { const text = await res.text(); let body={}; try { body = text ? JSON.parse(text) : {}; } catch { throw new Error(text || "Unreadable response."); } if (!res.ok) throw new Error(body.error || "Request failed."); return body; }
  async function loadFiles(targetFolderId=folderId, q="") { setDriveLoading(true); setDriveError(""); try { const url = q.trim() ? `/api/drive/list?q=${encodeURIComponent(q.trim())}` : `/api/drive/list?folderId=${encodeURIComponent(targetFolderId || "root")}`; const body = await apiJson(await fetch(url)); setFiles(body.files || []); } catch (e) { setFiles([]); setDriveError(e.message || "Could not load files."); } finally { setDriveLoading(false); } }
  async function createDriveFolder(name, folders=[], parentId="root") { return await apiJson(await fetch("/api/drive/folder", { method:"POST", body: JSON.stringify({ name, folders, parentId }) })); }
  function uploadWithProgress(file, folderId, onProgress) { return new Promise((resolve, reject) => { const xhr = new XMLHttpRequest(); const form = new FormData(); form.append("file", file); if (folderId && folderId !== "root") form.append("folderId", folderId); xhr.upload.addEventListener("progress", (e) => { if (e.lengthComputable) onProgress(Math.round((e.loaded/e.total)*100)); }); xhr.onload = () => { try { const body = JSON.parse(xhr.responseText || "{}"); xhr.status >= 200 && xhr.status < 300 ? resolve(body) : reject(new Error(body.error || "Upload failed.")); } catch { reject(new Error("Upload returned unreadable response.")); } }; xhr.onerror = () => reject(new Error("Network upload failed.")); xhr.open("POST", "/api/drive/upload"); xhr.send(form); }); }

  async function createService(form) {
    if (!isAdmin) return showToast("error", "Admin only", "Only Denzel and Talicia can create services.");
    const template = data.templates.find((t) => t.id === form.templateId); if (!template) return;
    const dateLabel = new Date(`${form.date}T12:00:00`).toLocaleDateString("en-US", { month:"short", day:"2-digit", year:"numeric" });
    const title = form.title?.trim() || `${dateLabel} ${template.name}`;
    try {
      showToast("info", "Creating service", "Building folders, videos, and checklist.");
      let driveFolder = null, childMap = {};
      if (form.createFolders) { const drive = await createDriveFolder(title, template.folders, "root"); driveFolder = drive.folder; childMap = Object.fromEntries((drive.children || []).map((c) => [c.name, c.id])); }
      setData((draft) => {
        const serviceId = uid("service");
        const service = { id: serviceId, templateId: template.id, title, date: form.date, time: form.time || template.time, status:"Planned", assignedTo: form.assignedTo || currentUser.name, folderId: driveFolder?.id || null, folderLink: driveFolder?.webViewLink || null, folders: childMap, checklist: template.checklist.map((text) => ({ id: uid("step"), text, done:false })), createdBy: currentUser.name, createdAt: new Date().toISOString() };
        const videos = template.suggestedVideos.map((v) => ({ id: uid("video"), serviceId, title:v.title, category:v.category, status:v.status, assignedTo:v.assignedTo, folderId: childMap["02 Raw Video"] || childMap["02 Raw Worship Video"] || childMap["02 Photos"] || driveFolder?.id || null, fileId:null, webViewLink:null, thumbnailLink:null, createdAt:new Date().toISOString() }));
        draft.services = [service, ...draft.services]; draft.videos = [...videos, ...draft.videos]; return draft;
      }, `created service "${title}"`);
      setModal(null); setActive("services"); showToast("success", "Service created", `${title} is ready.`);
      if (driveFolder?.id) { setFolderId(driveFolder.id); setFolderStack([{ id:"root", name:"My Drive" }, { id:driveFolder.id, name:title }]); loadFiles(driveFolder.id); }
    } catch(e) { showToast("error", "Could not create service", e.message); }
  }
  function updateService(id, patch) { setData((d) => { d.services = d.services.map((s) => s.id === id ? { ...s, ...patch } : s); return d; }, "updated a service"); }
  function deleteService(service) { if (!isAdmin) return showToast("error","Admin only","Only admins can delete services."); if (!confirm(`Delete "${service.title}" from the app?`)) return; setData((d) => { d.services = d.services.filter((s) => s.id !== service.id); d.videos = d.videos.filter((v) => v.serviceId !== service.id); return d; }, `deleted service "${service.title}"`); }
  function toggleChecklist(serviceId, stepId) { setData((d) => { d.services = d.services.map((s) => s.id !== serviceId ? s : { ...s, checklist: s.checklist.map((step) => step.id === stepId ? { ...step, done: !step.done } : step) }); return d; }, "updated checklist"); }
  function addVideo(form) { if (!isAdmin) return showToast("error","Admin only","Only admins can create videos."); setData((d) => { d.videos = [{ id: uid("video"), title: form.title, serviceId: form.serviceId || null, category: form.category, status: form.status || "Needs upload", assignedTo: form.assignedTo || currentUser.name, folderId: form.folderId || null, fileId:null, webViewLink:null, thumbnailLink:null, createdAt:new Date().toISOString() }, ...d.videos]; return d; }, `created video "${form.title}"`); setModal(null); showToast("success","Video created","The video was added."); }
  function updateVideo(id, patch, action="updated video") { setData((d) => { d.videos = d.videos.map((v) => v.id === id ? { ...v, ...patch } : v); return d; }, action); }
  function deleteVideo(video) { if (!isAdmin) return showToast("error","Admin only","Only admins can delete videos."); if (!confirm(`Delete "${video.title}" from the tracker?`)) return; setData((d) => { d.videos = d.videos.filter((v) => v.id !== video.id); return d; }, `deleted video "${video.title}"`); }
  async function uploadVideoFile(video, file, setProgress) { try { setProgress(2); const uploaded = await uploadWithProgress(file, video.folderId || "root", setProgress); updateVideo(video.id, { status:"Uploaded", fileId:uploaded.id, webViewLink:uploaded.webViewLink, thumbnailLink:uploaded.thumbnailLink || null, uploadedAt:new Date().toISOString(), uploadedBy:currentUser.name }, `uploaded video "${video.title}"`); setModal(null); showToast("success","Upload complete",`${video.title} is uploaded.`); } catch(e) { showToast("error","Upload failed",e.message); } }
  async function trashDriveItem(item) { if (!isAdmin) return showToast("error","Admin only","Only admins can trash Drive files."); if (!confirm(`Move "${item.name}" to trash?`)) return; try { await apiJson(await fetch("/api/drive/delete", { method:"POST", body: JSON.stringify({ fileId:item.id }) })); showToast("success","Moved to trash",item.name); loadFiles(); } catch(e){ showToast("error","Could not trash file",e.message); } }
  async function renameDriveItem(item) { const name = prompt("Rename item", item.name); if (!name || name === item.name) return; try { await apiJson(await fetch("/api/drive/rename", { method:"POST", body: JSON.stringify({ fileId:item.id, name }) })); showToast("success","Renamed",name); loadFiles(); } catch(e){ showToast("error","Could not rename",e.message); } }
  function openFolder(item) { setFolderId(item.id); setFolderStack((s) => [...s, { id:item.id, name:item.name }]); setFileSearch(""); loadFiles(item.id); }
  function goToCrumb(crumb, index) { setFolderId(crumb.id); setFolderStack((s) => s.slice(0, index+1)); setFileSearch(""); loadFiles(crumb.id); }
  async function logout() { await fetch("/api/logout", { method:"POST" }); window.location.href = "/"; }

  if (loading || !currentUser) return <main className="grid min-h-screen place-items-center text-white"><div className="text-center"><Loader2 className="mx-auto animate-spin text-sky-100" size={34}/><p className="mt-4 text-sm text-white/45">Loading your workspace...</p></div></main>;
  const activeNav = nav.find(([id]) => id === active) || nav[0]; const ActiveIcon = activeNav[2];

  return (
    <main className="relative min-h-screen overflow-hidden text-white">
      <div className="aura pointer-events-none absolute left-[-12rem] top-[-12rem] h-[34rem] w-[34rem] rounded-full bg-sky-400/15 blur-3xl" />
      <div className="pointer-events-none absolute right-[-16rem] top-[8rem] h-[38rem] w-[38rem] rounded-full bg-violet-500/14 blur-3xl" />
      <div className="relative z-10 flex min-h-screen">
        <aside className={cx("fixed inset-y-0 left-0 z-40 w-[18.5rem] border-r border-white/10 bg-black/48 p-4 backdrop-blur-2xl transition lg:sticky lg:top-0 lg:translate-x-0", sidebarOpen ? "translate-x-0" : "-translate-x-full")}>
          <div className="flex items-center justify-between gap-3"><button onClick={() => setActive("home")} className="flex items-center gap-3 text-left"><img src="/fpc-mark.png" alt="" className="h-12 w-12 rounded-2xl bg-white object-cover p-1"/><div><p className="text-xs uppercase tracking-[0.22em] text-white/35">FPC Wichita</p><h1 className="font-semibold">Media Command</h1></div></button><button onClick={() => setSidebarOpen(false)} className="lg:hidden"><X size={18}/></button></div>
          <nav className="mt-8 space-y-1.5">{nav.map(([id,label,Icon]) => <button key={id} onClick={() => {setActive(id); setSidebarOpen(false);}} className={cx("flex w-full items-center gap-3 rounded-2xl px-4 py-3 text-left text-sm transition", active === id ? "bg-white text-black" : "text-white/58 hover:bg-white/10 hover:text-white")}><Icon size={18}/><span className="flex-1">{label}</span>{active === id && <ChevronRight size={15}/>}</button>)}</nav>
          <div className="absolute bottom-4 left-4 right-4 space-y-3"><div className="rounded-2xl border border-white/10 bg-white/[0.04] p-4"><div className="flex items-center gap-3"><div className={`grid h-10 w-10 place-items-center rounded-2xl bg-gradient-to-br ${currentUser.color} text-xs font-bold`}>{currentUser.initials}</div><div><p className="font-semibold">{currentUser.name}</p><p className="text-xs capitalize text-white/40">{currentUser.role} · {source} · {saveState}</p></div></div></div><button onClick={logout} className="flex w-full items-center justify-center gap-2 rounded-2xl bg-white/10 px-4 py-3 text-sm text-white/70"><LogOut size={16}/>Logout</button></div>
        </aside>
        {sidebarOpen && <button className="fixed inset-0 z-30 bg-black/55 lg:hidden" onClick={() => setSidebarOpen(false)} />}
        <section className="min-w-0 flex-1 p-4 sm:p-6 lg:p-8"><header className="mb-6 flex flex-col gap-4 xl:flex-row xl:items-center xl:justify-between"><div className="flex items-center gap-3"><button onClick={() => setSidebarOpen(true)} className="rounded-2xl border border-white/10 bg-white/10 p-3 lg:hidden"><Menu size={20}/></button><div><p className="flex items-center gap-2 text-sm text-white/45"><ActiveIcon size={16}/>Working as {currentUser.name}</p><h2 className="text-3xl font-semibold tracking-tight sm:text-5xl">{activeNav[1]}</h2></div></div><div className="flex flex-col gap-3 sm:flex-row"><button onClick={() => setModal({ type:"create-service" })} className="flex items-center justify-center gap-2 rounded-2xl bg-white px-5 py-3 text-sm font-semibold text-black"><Plus size={17}/>Create Service</button><button onClick={() => setModal({ type:"add-video" })} className="flex items-center justify-center gap-2 rounded-2xl border border-white/10 bg-white/10 px-5 py-3 text-sm font-semibold"><Film size={17}/>Add Video</button></div></header>
          <AnimatePresence mode="wait">
            {active === "home" && <Page keyName="home"><HomeView data={data} timeContext={timeContext} setActive={setActive} openCreateService={() => setModal({ type:"create-service", templateId:timeContext.templateId })} videosByService={videosByService} updateVideo={updateVideo}/></Page>}
            {active === "services" && <Page keyName="services"><ServicesView data={data} videosByService={videosByService} openCreate={() => setModal({ type:"create-service" })} openService={(service) => setModal({ type:"service-detail", service })} deleteService={deleteService} updateService={updateService} isAdmin={isAdmin}/></Page>}
            {active === "videos" && <Page keyName="videos"><VideosView data={data} updateVideo={updateVideo} deleteVideo={deleteVideo} openUpload={(video) => setModal({ type:"upload-video", video })} openPreview={(video) => setModal({ type:"preview-video", video })} openAdd={() => setModal({ type:"add-video" })} isAdmin={isAdmin}/></Page>}
            {active === "calendar" && <Page keyName="calendar"><CalendarView data={data} openCreate={() => setModal({ type:"create-service" })}/></Page>}
            {active === "checklists" && <Page keyName="checklists"><ChecklistsView data={data} toggleChecklist={toggleChecklist} openService={(service) => setModal({ type:"service-detail", service })}/></Page>}
            {active === "files" && <Page keyName="files"><FilesView driveFolders={driveFolders} driveFiles={driveFiles} loading={driveLoading} error={driveError} folderStack={folderStack} goToCrumb={goToCrumb} openFolder={openFolder} search={fileSearch} setSearch={setFileSearch} loadFiles={loadFiles} folderId={folderId} uploadRef={uploadRef} uploadFile={(file) => file && setModal({ type:"upload-file", file, folderId })} trashDriveItem={trashDriveItem} renameDriveItem={renameDriveItem} isAdmin={isAdmin}/></Page>}
            {active === "gear" && <Page keyName="gear"><GearView data={data}/></Page>}
            {active === "access" && <Page keyName="access"><AccessView data={data}/></Page>}
            {active === "people" && <Page keyName="people"><PeopleView data={data} resetData={resetData} isAdmin={isAdmin}/></Page>}
          </AnimatePresence></section>
      </div>
      <AnimatePresence>{modal?.type === "create-service" && <CreateServiceModal data={data} defaultTemplateId={modal.templateId} currentUser={currentUser} onClose={() => setModal(null)} onCreate={createService}/>} {modal?.type === "add-video" && <AddVideoModal data={data} onClose={() => setModal(null)} onAdd={addVideo}/>} {modal?.type === "upload-video" && <UploadVideoModal video={modal.video} onClose={() => setModal(null)} onUpload={uploadVideoFile}/>} {modal?.type === "upload-file" && <GenericUploadModal file={modal.file} folderId={modal.folderId} onClose={() => setModal(null)} uploadWithProgress={uploadWithProgress} onDone={() => { loadFiles(folderId); showToast("success", "Upload complete", modal.file.name); }}/>} {modal?.type === "preview-video" && <PreviewModal video={modal.video} onClose={() => setModal(null)}/>} {modal?.type === "service-detail" && <ServiceDetailModal service={data.services.find((s) => s.id === modal.service.id) || modal.service} videos={videosByService[modal.service.id] || []} onClose={() => setModal(null)} updateService={updateService} toggleChecklist={toggleChecklist} updateVideo={updateVideo} openUpload={(video) => setModal({ type:"upload-video", video })} openPreview={(video) => setModal({ type:"preview-video", video })}/>}</AnimatePresence>
      <AnimatePresence>{toast && <Toast toast={toast}/>}</AnimatePresence>
    </main>
  );
}

function Page({ children, keyName }) { return <motion.div key={keyName} initial={{ opacity:0, y:18, filter:"blur(8px)" }} animate={{ opacity:1, y:0, filter:"blur(0px)" }} exit={{ opacity:0, y:-10, filter:"blur(6px)" }} transition={{ duration:.25 }}>{children}</motion.div>; }

function HomeView({ data, timeContext, setActive, openCreateService, videosByService, updateVideo }) {
  const activeVideos = data.videos.filter((v) => ["Needs upload", "Uploaded", "Needs edit", "Ready to post"].includes(v.status)).slice(0, 6);
  const recentServices = data.services.slice(0, 4);
  return <div className="space-y-6"><section className="grid gap-5 xl:grid-cols-[1.2fr_.8fr]"><Card className="relative overflow-hidden p-6 sm:p-8"><div className="absolute right-[-4rem] top-[-8rem] h-[21rem] w-[21rem] rounded-full bg-sky-400/20 blur-3xl"/><div className="relative z-10 max-w-3xl"><div className="mb-6 inline-flex items-center gap-2 rounded-full border border-white/10 bg-white/10 px-3 py-2 text-xs text-sky-100"><Sparkles size={14}/>Smart dashboard</div><h3 className="text-balance text-4xl font-semibold tracking-tight sm:text-6xl">{timeContext.title}</h3><p className="mt-5 max-w-2xl text-sm leading-7 text-white/58 sm:text-base">{timeContext.body}</p><div className="mt-7 flex flex-wrap gap-3"><button onClick={timeContext.service ? () => setActive("services") : openCreateService} className="rounded-2xl bg-white px-5 py-3 text-sm font-semibold text-black">{timeContext.service ? "Open Service" : "Create Service"}</button><button onClick={() => setActive("videos")} className="rounded-2xl border border-white/10 bg-white/10 px-5 py-3 text-sm font-semibold">Review Videos</button></div></div></Card><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-1"><Soft><p className="text-sm text-white/45">Services</p><p className="mt-2 text-4xl font-semibold">{data.services.length}</p></Soft><Soft><p className="text-sm text-white/45">Videos needing attention</p><p className="mt-2 text-4xl font-semibold">{activeVideos.length}</p></Soft><Soft><p className="text-sm text-white/45">Gear items</p><p className="mt-2 text-4xl font-semibold">{data.gear.length}</p></Soft></div></section><section className="grid gap-5 xl:grid-cols-[.9fr_1.1fr]"><Card><Section eyebrow="Today" title="Focus list"/>{activeVideos.length === 0 ? <Empty icon={CheckCircle2} title="Nothing urgent." body="Create a service or add videos when new media work starts."/> : <div className="space-y-3">{activeVideos.map((v) => <VideoRow key={v.id} video={v} updateVideo={updateVideo}/>)}</div>}</Card><Card><Section eyebrow="Services" title="Recent services"/>{recentServices.length === 0 ? <Empty icon={CalendarDays} title="No services created yet." body="Start by creating Sunday Morning, Sunday Evening, Wednesday Night, or Custom." action={<button onClick={openCreateService} className="rounded-2xl bg-white px-4 py-2 text-sm font-semibold text-black">Create Service</button>}/> : <div className="grid gap-3 md:grid-cols-2">{recentServices.map((s) => <button key={s.id} onClick={() => setActive("services")} className="rounded-[1.3rem] border border-white/10 bg-white/[0.04] p-4 text-left"><p className="font-semibold">{s.title}</p><p className="mt-1 text-sm text-white/45">{prettyDate(s.date)} · {s.time}</p><p className="mt-3 text-sm text-white/45">{(videosByService[s.id] || []).length} videos tracked</p></button>)}</div>}</Card></section></div>;
}
function VideoRow({ video, updateVideo }) { return <div className="rounded-[1.2rem] border border-white/10 bg-white/[0.04] p-4"><div className="flex items-start justify-between gap-3"><div><p className="font-semibold">{video.title}</p><p className="mt-1 text-sm text-white/42">{video.category}</p></div><Pill tone={video.status === "Ready to post" ? "green" : "orange"}>{video.status}</Pill></div><div className="mt-4 flex flex-wrap gap-2">{["Uploaded","Needs edit","Ready to post","Posted"].map((s) => <button key={s} onClick={() => updateVideo(video.id, { status:s }, `set ${video.title} to ${s}`)} className="rounded-xl bg-white/10 px-3 py-2 text-xs text-white/70">{s}</button>)}</div></div>; }

function ServicesView({ data, videosByService, openCreate, openService, deleteService, updateService, isAdmin }) { return <div className="space-y-6"><Card><div className="flex flex-col gap-4 sm:flex-row sm:items-end sm:justify-between"><div><p className="text-xs uppercase tracking-[0.25em] text-sky-100/45">Services</p><h2 className="mt-1 text-2xl font-semibold">Create and manage real services</h2><p className="mt-2 max-w-2xl text-sm leading-6 text-white/48">A service creates a folder structure, checklist, and suggested videos.</p></div><button onClick={openCreate} className="rounded-2xl bg-white px-4 py-3 text-sm font-semibold text-black">Create Service</button></div></Card>{data.services.length === 0 ? <Empty icon={CalendarDays} title="No services yet." body="Create Sunday Morning, Sunday Evening, Wednesday Night, or a custom service." action={<button onClick={openCreate} className="rounded-2xl bg-white px-5 py-3 text-sm font-semibold text-black">Create first service</button>}/> : <div className="grid gap-5 xl:grid-cols-2">{data.services.map((s) => { const vids = videosByService[s.id] || []; const done = s.checklist?.filter((x) => x.done).length || 0; const total = s.checklist?.length || 1; const pct = Math.round(done/total*100); return <Card key={s.id}><div className="flex items-start justify-between gap-4"><button onClick={() => openService(s)} className="text-left"><p className="text-sm text-sky-100">{prettyDate(s.date)} · {s.time}</p><h3 className="mt-1 text-2xl font-semibold">{s.title}</h3><p className="mt-2 text-sm text-white/45">Assigned to {s.assignedTo}</p></button><Pill tone={s.status === "Posted" ? "green" : "orange"}>{s.status}</Pill></div><div className="mt-5 grid gap-3 sm:grid-cols-3"><Soft><p className="text-xs text-white/40">Videos</p><p className="mt-1 text-2xl font-semibold">{vids.length}</p></Soft><Soft><p className="text-xs text-white/40">Checklist</p><p className="mt-1 text-2xl font-semibold">{pct}%</p></Soft><Soft><p className="text-xs text-white/40">Folder</p><p className="mt-1 text-sm font-semibold">{s.folderId ? "Created" : "None"}</p></Soft></div><div className="mt-5 flex flex-wrap gap-2"><button onClick={() => openService(s)} className="rounded-xl bg-white px-3 py-2 text-xs font-semibold text-black">Open</button>{s.folderLink && <a href={s.folderLink} target="_blank" className="rounded-xl bg-white/10 px-3 py-2 text-xs text-white/70">Drive Folder</a>}{serviceStatuses.map((status) => <button key={status} onClick={() => updateService(s.id, { status })} className="rounded-xl bg-white/10 px-3 py-2 text-xs text-white/70">{status}</button>)}{isAdmin && <button onClick={() => deleteService(s)} className="rounded-xl bg-red-500/15 px-3 py-2 text-xs text-red-100">Delete</button>}</div></Card>; })}</div>}</div>; }

function VideosView({ data, updateVideo, deleteVideo, openUpload, openPreview, openAdd, isAdmin }) { const groups = ["Needs recording","Needs upload","Uploaded","Needs edit","Ready to post","Posted"]; return <div className="space-y-6"><Card><div className="flex flex-col gap-4 sm:flex-row sm:items-end sm:justify-between"><div><p className="text-xs uppercase tracking-[0.25em] text-sky-100/45">Videos</p><h2 className="mt-1 text-2xl font-semibold">Track every video clearly</h2><p className="mt-2 max-w-2xl text-sm leading-6 text-white/48">Mark what needs recording, upload, editing, posting, or preview.</p></div><button onClick={openAdd} className="rounded-2xl bg-white px-4 py-3 text-sm font-semibold text-black">Add Video</button></div></Card><div className="grid gap-5 xl:grid-cols-3">{groups.map((g) => { const videos = data.videos.filter((v) => v.status === g); return <Card key={g} className="min-h-[18rem]"><Section title={g} action={<Pill>{videos.length}</Pill>}/><div className="space-y-3">{videos.length === 0 && <p className="rounded-2xl border border-dashed border-white/10 p-5 text-sm text-white/35">Nothing here.</p>}{videos.map((v) => <VideoCard key={v.id} video={v} services={data.services} updateVideo={updateVideo} deleteVideo={deleteVideo} openUpload={openUpload} openPreview={openPreview} isAdmin={isAdmin}/>)}</div></Card>; })}</div></div>; }
function VideoCard({ video, services, updateVideo, deleteVideo, openUpload, openPreview, isAdmin }) { const service = services.find((s) => s.id === video.serviceId); return <motion.div layout className="rounded-[1.3rem] border border-white/10 bg-white/[0.04] p-4"><div className="flex items-start justify-between gap-3"><div><p className="font-semibold">{video.title}</p><p className="mt-1 text-sm text-white/40">{service?.title || "No service"} · {video.category}</p></div><Pill>{video.assignedTo}</Pill></div>{video.thumbnailLink && <button onClick={() => openPreview(video)} className="mt-4 block w-full overflow-hidden rounded-2xl bg-black/25"><img src={video.thumbnailLink} alt="" className="h-36 w-full object-cover"/></button>}<div className="mt-4 flex flex-wrap gap-2">{!video.fileId ? <button onClick={() => openUpload(video)} className="rounded-xl bg-white px-3 py-2 text-xs font-semibold text-black">Upload</button> : <button onClick={() => openPreview(video)} className="flex items-center gap-1 rounded-xl bg-white px-3 py-2 text-xs font-semibold text-black"><Play size={13}/>Preview</button>}<select value={video.status} onChange={(e) => updateVideo(video.id, { status:e.target.value }, `set ${video.title} to ${e.target.value}`)} className="rounded-xl border border-white/10 bg-black/40 px-3 py-2 text-xs text-white outline-none">{videoStatuses.map((s) => <option key={s}>{s}</option>)}</select>{video.webViewLink && <a href={video.webViewLink} target="_blank" className="rounded-xl bg-white/10 px-3 py-2 text-xs text-white/70">Drive</a>}{isAdmin && <button onClick={() => deleteVideo(video)} className="rounded-xl bg-red-500/15 px-3 py-2 text-xs text-red-100">Delete</button>}</div></motion.div>; }

function CalendarView({ data, openCreate }) { const days = ["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"]; return <div className="space-y-6"><Card><div className="flex flex-col gap-4 sm:flex-row sm:items-end sm:justify-between"><div><p className="text-xs uppercase tracking-[0.25em] text-sky-100/45">Calendar</p><h2 className="mt-1 text-2xl font-semibold">Weekly posting rhythm</h2></div><button onClick={openCreate} className="rounded-2xl bg-white px-4 py-3 text-sm font-semibold text-black">Create Service</button></div></Card><div className="grid gap-4 xl:grid-cols-7">{days.map((day) => { const posts = data.weeklyPosts.filter((p) => p.day.includes(day)); const services = data.services.filter((s) => new Date(`${s.date}T12:00:00`).toLocaleDateString("en-US", { weekday:"long" }) === day); return <Card key={day} className="min-h-[22rem] p-4"><h3 className="font-semibold">{day}</h3><div className="mt-4 space-y-3">{services.map((s) => <div key={s.id} className="rounded-2xl bg-sky-400/12 p-3"><p className="text-xs text-sky-100">{s.time}</p><p className="mt-1 text-sm font-semibold">{s.title}</p></div>)}{posts.map((p) => <div key={p.id} className="rounded-2xl bg-white/[0.05] p-3"><p className="text-xs text-white/40">{p.time}</p><p className="mt-1 text-sm font-semibold">{p.title}</p><p className="mt-1 text-xs text-white/35">{p.type}</p></div>)}{posts.length + services.length === 0 && <p className="text-sm text-white/28">Nothing scheduled.</p>}</div></Card>; })}</div></div>; }
function ChecklistsView({ data, toggleChecklist, openService }) { const services = data.services.filter((s) => s.checklist?.length); return <div className="space-y-6"><Card><Section eyebrow="Checklists" title="Service checklists"/><p className="text-sm leading-6 text-white/48">Each service has its own checklist generated from the selected template.</p></Card>{services.length === 0 ? <Empty icon={ClipboardList} title="No checklists yet." body="Create a service and a checklist will be generated automatically."/> : <div className="grid gap-5 xl:grid-cols-2">{services.map((s) => { const done = s.checklist.filter((i) => i.done).length; const pct = Math.round(done/s.checklist.length*100); return <Card key={s.id}><div className="flex items-start justify-between gap-3"><button onClick={() => openService(s)} className="text-left"><h3 className="text-xl font-semibold">{s.title}</h3><p className="mt-1 text-sm text-white/42">{done}/{s.checklist.length} done</p></button><Pill tone={pct === 100 ? "green" : "sky"}>{pct}%</Pill></div><div className="mt-5 space-y-3">{s.checklist.map((step) => <button key={step.id} onClick={() => toggleChecklist(s.id, step.id)} className={cx("flex w-full gap-3 rounded-[1.15rem] border p-4 text-left text-sm", step.done ? "border-emerald-300/25 bg-emerald-400/10" : "border-white/10 bg-white/[0.04]")}><span className={cx("grid h-6 w-6 shrink-0 place-items-center rounded-full", step.done ? "bg-emerald-300 text-black" : "bg-white/10")}>{step.done && <Check size={14}/>}</span>{step.text}</button>)}</div></Card>; })}</div>}</div>; }

function FilesView({ driveFolders, driveFiles, loading, error, folderStack, goToCrumb, openFolder, search, setSearch, loadFiles, folderId, uploadRef, uploadFile, trashDriveItem, renameDriveItem, isAdmin }) { return <div className="space-y-6"><Card><div className="flex flex-col gap-4 xl:flex-row xl:items-center xl:justify-between"><div><p className="text-xs uppercase tracking-[0.25em] text-sky-100/45">Files</p><div className="mt-2 flex flex-wrap gap-1 text-sm text-white/52">{folderStack.map((c,i) => <button key={`${c.id}-${i}`} onClick={() => goToCrumb(c,i)} className="rounded-full px-2 py-1 hover:bg-white/10 hover:text-white">{c.name}{i < folderStack.length - 1 && <span className="ml-2 text-white/25">/</span>}</button>)}</div></div><div className="flex flex-col gap-3 sm:flex-row"><div className="flex min-w-[16rem] items-center gap-2 rounded-2xl border border-white/10 bg-black/25 px-4 py-3"><Search size={17} className="text-white/35"/><input value={search} onChange={(e) => setSearch(e.target.value)} onKeyDown={(e) => e.key === "Enter" && loadFiles(folderId, search)} placeholder="Search files..." className="w-full bg-transparent text-sm outline-none placeholder:text-white/30"/></div><button onClick={() => loadFiles(folderId, search)} className="rounded-2xl border border-white/10 bg-white/10 px-4 py-3"><RefreshCw size={17} className={loading ? "animate-spin" : ""}/></button><label className="flex cursor-pointer items-center justify-center gap-2 rounded-2xl bg-white px-4 py-3 text-sm font-semibold text-black"><Upload size={17}/>Upload<input ref={uploadRef} type="file" className="hidden" onChange={(e) => uploadFile(e.target.files?.[0])}/></label></div></div>{error && <div className="mt-4 rounded-2xl border border-red-400/20 bg-red-500/10 p-4 text-sm text-red-100">{error}</div>}</Card>{loading ? <div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{Array.from({length:8}).map((_,i) => <div key={i} className="h-48 animate-pulse rounded-[1.4rem] bg-white/[0.05]"/>)}</div> : driveFolders.length + driveFiles.length === 0 ? <Empty icon={Cloud} title="No files here." body="Upload files or open a service folder."/> : <div className="space-y-7">{driveFolders.length > 0 && <FileGroup title="Folders" items={driveFolders} isFolder openFolder={openFolder} trashDriveItem={trashDriveItem} renameDriveItem={renameDriveItem} isAdmin={isAdmin}/>} {driveFiles.length > 0 && <FileGroup title="Files" items={driveFiles} trashDriveItem={trashDriveItem} renameDriveItem={renameDriveItem} isAdmin={isAdmin}/>}</div>}</div>; }
function FileGroup({ title, items, isFolder, openFolder, trashDriveItem, renameDriveItem, isAdmin }) { return <Card><Section title={title} action={<Pill>{items.length}</Pill>}/><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{items.map((item) => <motion.div key={item.id} layout whileHover={{ y:-4 }} className="rounded-[1.3rem] border border-white/10 bg-white/[0.04] p-4"><div className="mb-4 flex h-28 items-center justify-center overflow-hidden rounded-[1rem] bg-black/25">{item.thumbnailLink ? <img src={item.thumbnailLink} alt="" className="h-full w-full object-cover"/> : isFolder ? <Folder size={42} className="text-sky-100"/> : <File size={42} className="text-white/65"/>}</div><p className="truncate font-semibold">{item.name}</p><p className="mt-1 text-xs text-white/35">{isFolder ? "Folder" : item.size ? `${Math.round(Number(item.size)/1024)} KB` : "File"}</p><div className="mt-4 flex flex-wrap gap-2">{isFolder ? <button onClick={() => openFolder(item)} className="rounded-xl bg-white px-3 py-2 text-xs font-semibold text-black">Open</button> : <a href={`/api/drive/download?fileId=${item.id}`} className="rounded-xl bg-white px-3 py-2 text-xs font-semibold text-black">Download</a>}{item.webViewLink && <a href={item.webViewLink} target="_blank" className="rounded-xl bg-white/10 px-3 py-2 text-xs text-white/70">View</a>}<button onClick={() => renameDriveItem(item)} className="rounded-xl bg-white/10 px-3 py-2 text-xs text-white/70">Rename</button>{isAdmin && <button onClick={() => trashDriveItem(item)} className="rounded-xl bg-red-500/15 px-3 py-2 text-xs text-red-100">Trash</button>}</div></motion.div>)}</div></Card>; }

function GearView({ data }) { return <div className="space-y-6"><Card><Section eyebrow="Gear" title="Camera and equipment settings"/></Card><div className="grid gap-5 xl:grid-cols-3">{data.gear.map((g) => <Card key={g.id}><div className="flex items-start justify-between gap-3"><div><Pill>{g.category}</Pill><h3 className="mt-3 text-xl font-semibold">{g.name}</h3><p className="mt-1 text-sm text-white/42">{g.location}</p></div><Pill tone={g.status === "Ready" ? "green" : "orange"}>{g.status}</Pill></div><div className="mt-5 space-y-2">{g.settings.map((s) => <div key={s.label} className="flex items-center justify-between gap-4 rounded-2xl bg-black/24 px-4 py-3 text-sm"><span className="text-white/42">{s.label}</span><span className="text-right font-medium">{s.value}</span></div>)}</div><p className="mt-4 text-sm leading-5 text-white/45">{g.notes}</p></Card>)}</div></div>; }
function AccessView({ data }) { const [revealed, setRevealed] = useState({}); return <div className="space-y-6"><Card><Section eyebrow="Access" title="Team account reference"/><p className="text-sm text-white/48">Private convenience area. For higher security later, connect a real password manager.</p></Card><div className="grid gap-5 xl:grid-cols-3">{data.access.map((item) => { const show = revealed[item.id]; return <Card key={item.id}><div className="flex items-start justify-between gap-3"><div><Pill>{item.category}</Pill><h3 className="mt-3 text-xl font-semibold">{item.name}</h3></div><LockKeyhole size={20} className="text-sky-100"/></div><AccessRow label="Username" value={item.username}/><AccessRow label="Password" value={show ? item.password : "••••••••••••"}/><p className="mt-4 text-sm text-white/45">{item.notes}</p><div className="mt-5 flex gap-2"><button onClick={() => setRevealed((c) => ({ ...c, [item.id]: !c[item.id] }))} className="flex flex-1 items-center justify-center gap-2 rounded-2xl bg-white/10 px-3 py-2 text-sm text-white/72">{show ? <EyeOff size={15}/> : <Eye size={15}/>} {show ? "Hide" : "Reveal"}</button><button onClick={() => navigator.clipboard?.writeText(item.password)} className="rounded-2xl bg-white px-3 py-2 text-black"><Copy size={15}/></button></div></Card>; })}</div></div>; }
function AccessRow({ label, value }) { return <div className="mt-4 rounded-2xl bg-black/22 p-3"><p className="text-xs uppercase tracking-[0.2em] text-white/30">{label}</p><p className="mt-1 truncate text-sm text-white/75">{value}</p></div>; }
function PeopleView({ data, resetData, isAdmin }) { return <div className="space-y-6"><Card><Section eyebrow="People" title="Team members and permissions" action={isAdmin && <button onClick={() => confirm("Reset app data?") && resetData()} className="rounded-2xl bg-white/10 px-4 py-2 text-sm text-white/70">Reset data</button>}/><p className="text-sm leading-6 text-white/48">Denzel and Talicia can create/delete. Everyone can handle statuses, uploads, previews, and checklists.</p></Card><div className="grid gap-5 xl:grid-cols-5">{data.people.map((p) => <Card key={p.id} className="text-center"><div className={`mx-auto grid h-16 w-16 place-items-center rounded-2xl bg-gradient-to-br ${p.color} font-bold`}>{p.initials}</div><h3 className="mt-4 font-semibold">{p.name}</h3><p className="mt-1 text-sm capitalize text-white/42">{p.role}</p></Card>)}</div></div>; }

function ModalShell({ children, onClose, title, wide=false }) { return <motion.div className="fixed inset-0 z-50 grid place-items-start overflow-y-auto bg-black/72 p-4 pt-[7vh] backdrop-blur-md sm:place-items-center sm:pt-4" initial={{ opacity:0 }} animate={{ opacity:1 }} exit={{ opacity:0 }} onMouseDown={onClose}><motion.div initial={{ opacity:0, y:24, scale:.97 }} animate={{ opacity:1, y:0, scale:1 }} exit={{ opacity:0, y:16, scale:.97 }} onMouseDown={(e) => e.stopPropagation()} className={cx("glass w-full overflow-hidden rounded-[1.75rem]", wide ? "max-w-6xl" : "max-w-2xl")}><div className="flex items-center justify-between border-b border-white/10 px-5 py-4"><div className="flex items-center gap-2 font-semibold"><Sparkles size={17} className="text-sky-100"/>{title}</div><button onClick={onClose} className="rounded-xl p-2 text-white/45 hover:bg-white/10"><X size={18}/></button></div>{children}</motion.div></motion.div>; }
function CreateServiceModal({ data, defaultTemplateId, currentUser, onClose, onCreate }) { const [templateId, setTemplateId] = useState(defaultTemplateId || data.templates[0]?.id || "custom"); const template = data.templates.find((t) => t.id === templateId) || data.templates[0]; const [date, setDate] = useState(todayInput()); const [time, setTime] = useState(template?.time || "7:00 PM"); const [title, setTitle] = useState(""); const [assignedTo, setAssignedTo] = useState(currentUser?.name || "Denzel"); const [createFolders, setCreateFolders] = useState(true); const [submitting, setSubmitting] = useState(false); useEffect(() => setTime(template?.time || "7:00 PM"), [templateId]); async function submit() { setSubmitting(true); await onCreate({ templateId, date, time, title, assignedTo, createFolders }); setSubmitting(false); } return <ModalShell onClose={onClose} title="Create Service" wide><div className="grid gap-0 xl:grid-cols-[.8fr_1.2fr]"><div className="border-b border-white/10 p-5 xl:border-b-0 xl:border-r"><p className="text-sm text-white/50">Choose the service type. The app creates the right checklist, videos, and Drive folders.</p><div className="mt-5 space-y-3">{data.templates.map((item) => <button key={item.id} onClick={() => setTemplateId(item.id)} className={cx("w-full rounded-[1.25rem] border p-4 text-left", templateId === item.id ? "border-sky-300/45 bg-sky-400/12" : "border-white/10 bg-white/[0.04] hover:bg-white/[0.08]")}><div className="flex items-center justify-between"><p className="font-semibold">{item.name}</p>{templateId === item.id && <Check size={17} className="text-sky-100"/>}</div><p className="mt-2 text-sm leading-5 text-white/45">{item.description}</p></button>)}</div></div><div className="p-5"><div className="grid gap-4 md:grid-cols-2"><label><span className="text-sm text-white/45">Date</span><input type="date" value={date} onChange={(e) => setDate(e.target.value)} className="mt-2 w-full rounded-2xl border border-white/10 bg-black/30 px-4 py-3 outline-none"/></label><label><span className="text-sm text-white/45">Time</span><input value={time} onChange={(e) => setTime(e.target.value)} className="mt-2 w-full rounded-2xl border border-white/10 bg-black/30 px-4 py-3 outline-none"/></label><label className="md:col-span-2"><span className="text-sm text-white/45">Custom title, optional</span><input value={title} onChange={(e) => setTitle(e.target.value)} placeholder={`${prettyDate(date)} ${template?.name || "Service"}`} className="mt-2 w-full rounded-2xl border border-white/10 bg-black/30 px-4 py-3 outline-none"/></label><label><span className="text-sm text-white/45">Lead person</span><select value={assignedTo} onChange={(e) => setAssignedTo(e.target.value)} className="mt-2 w-full rounded-2xl border border-white/10 bg-black/30 px-4 py-3 outline-none">{people.map((p) => <option key={p.id}>{p.name}</option>)}</select></label><button type="button" onClick={() => setCreateFolders(!createFolders)} className={cx("mt-7 rounded-2xl border px-4 py-3 text-left", createFolders ? "border-emerald-300/30 bg-emerald-400/10" : "border-white/10 bg-white/[0.04]")}><div className="flex items-center gap-2"><CheckCircle2 size={18}/><span className="font-semibold">{createFolders ? "Drive folders will be created" : "Do not create Drive folders"}</span></div></button></div><div className="mt-5 grid gap-4 md:grid-cols-2"><div className="rounded-[1.25rem] border border-white/10 bg-white/[0.04] p-4"><p className="font-semibold">Videos created</p><div className="mt-3 space-y-2">{template?.suggestedVideos.map((v) => <p key={v.title} className="text-sm text-white/50">• {v.title}</p>)}</div></div><div className="rounded-[1.25rem] border border-white/10 bg-white/[0.04] p-4"><p className="font-semibold">Folders created</p><div className="mt-3 max-h-36 space-y-2 overflow-y-auto">{template?.folders.map((f) => <p key={f} className="text-sm text-white/50">• {f}</p>)}</div></div></div><button onClick={submit} disabled={submitting} className="mt-5 flex w-full items-center justify-center gap-2 rounded-2xl bg-white px-5 py-3 font-semibold text-black disabled:opacity-60">{submitting ? <Loader2 className="animate-spin" size={18}/> : <WandSparkles size={18}/>} {submitting ? "Creating service..." : "Create Service"}</button></div></div></ModalShell>; }
function AddVideoModal({ data, onClose, onAdd }) { const [title,setTitle] = useState(""); const [serviceId,setServiceId] = useState(data.services[0]?.id || ""); const [category,setCategory] = useState(contentCategories[0].types[0]); const [status,setStatus] = useState("Needs upload"); const [assignedTo,setAssignedTo] = useState("Denzel"); return <ModalShell onClose={onClose} title="Add Video"><div className="space-y-4 p-5"><label><span className="text-sm text-white/45">Video title</span><input autoFocus value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Sermon recap, worship highlight..." className="mt-2 w-full rounded-2xl border border-white/10 bg-black/30 px-4 py-3 outline-none"/></label><div className="grid gap-4 md:grid-cols-2"><label><span className="text-sm text-white/45">Service</span><select value={serviceId} onChange={(e) => setServiceId(e.target.value)} className="mt-2 w-full rounded-2xl border border-white/10 bg-black/30 px-4 py-3 outline-none"><option value="">No service</option>{data.services.map((s) => <option key={s.id} value={s.id}>{s.title}</option>)}</select></label><label><span className="text-sm text-white/45">Assigned to</span><select value={assignedTo} onChange={(e) => setAssignedTo(e.target.value)} className="mt-2 w-full rounded-2xl border border-white/10 bg-black/30 px-4 py-3 outline-none">{people.map((p) => <option key={p.id}>{p.name}</option>)}</select></label><label><span className="text-sm text-white/45">Category</span><select value={category} onChange={(e) => setCategory(e.target.value)} className="mt-2 w-full rounded-2xl border border-white/10 bg-black/30 px-4 py-3 outline-none">{contentCategories.flatMap((c) => c.types).map((t) => <option key={t}>{t}</option>)}</select></label><label><span className="text-sm text-white/45">Status</span><select value={status} onChange={(e) => setStatus(e.target.value)} className="mt-2 w-full rounded-2xl border border-white/10 bg-black/30 px-4 py-3 outline-none">{videoStatuses.map((s) => <option key={s}>{s}</option>)}</select></label></div><button disabled={!title.trim()} onClick={() => onAdd({ title, serviceId, category, status, assignedTo })} className="w-full rounded-2xl bg-white px-5 py-3 font-semibold text-black disabled:opacity-50">Add Video</button></div></ModalShell>; }
function UploadVideoModal({ video, onClose, onUpload }) { const [file,setFile] = useState(null); const [progress,setProgress] = useState(0); return <ModalShell onClose={onClose} title={`Upload: ${video.title}`}><div className="p-5"><div className="rounded-[1.4rem] border border-dashed border-white/15 bg-white/[0.04] p-8 text-center"><Upload className="mx-auto text-white/35" size={42}/><h3 className="mt-4 text-xl font-semibold">Choose the video file</h3><p className="mt-2 text-sm text-white/45">Progress and completion will show clearly.</p><input type="file" accept="video/*,image/*" onChange={(e) => setFile(e.target.files?.[0] || null)} className="mt-5"/></div>{file && <p className="mt-4 text-sm text-white/55">{file.name}</p>}{progress > 0 && <div className="mt-5"><div className="flex justify-between text-sm text-white/55"><span>Uploading</span><span>{progress}%</span></div><div className="mt-2 h-3 overflow-hidden rounded-full bg-white/10"><motion.div initial={{width:0}} animate={{width:`${progress}%`}} className="h-full rounded-full bg-white"/></div></div>}<button disabled={!file || progress > 0} onClick={() => onUpload(video, file, setProgress)} className="mt-5 w-full rounded-2xl bg-white px-5 py-3 font-semibold text-black disabled:opacity-50">Upload and mark uploaded</button></div></ModalShell>; }
function GenericUploadModal({ file, folderId, onClose, uploadWithProgress, onDone }) { const [progress,setProgress] = useState(0); const [started,setStarted] = useState(false); async function start(){ setStarted(true); try { await uploadWithProgress(file, folderId, setProgress); onDone(); onClose(); } catch(e){ alert(e.message); setStarted(false); } } return <ModalShell onClose={onClose} title="Upload File"><div className="p-5"><h3 className="text-xl font-semibold">{file.name}</h3><p className="mt-2 text-sm text-white/45">Upload this file to the current Drive folder.</p>{started && <div className="mt-5"><div className="flex justify-between text-sm text-white/55"><span>Uploading</span><span>{progress}%</span></div><div className="mt-2 h-3 overflow-hidden rounded-full bg-white/10"><motion.div animate={{width:`${progress}%`}} className="h-full rounded-full bg-white"/></div></div>}<button onClick={start} disabled={started} className="mt-5 w-full rounded-2xl bg-white px-5 py-3 font-semibold text-black disabled:opacity-50">Start Upload</button></div></ModalShell>; }
function ServiceDetailModal({ service, videos, onClose, updateService, toggleChecklist, updateVideo, openUpload, openPreview }) { const done = service.checklist?.filter((s) => s.done).length || 0; const total = service.checklist?.length || 1; const pct = Math.round(done/total*100); return <ModalShell onClose={onClose} title={service.title} wide><div className="grid gap-0 xl:grid-cols-[.95fr_1.05fr]"><div className="border-b border-white/10 p-5 xl:border-b-0 xl:border-r"><p className="text-sm text-sky-100">{prettyDate(service.date)} · {service.time}</p><h3 className="mt-2 text-3xl font-semibold">{service.title}</h3><p className="mt-2 text-sm text-white/45">Assigned to {service.assignedTo}</p><div className="mt-5 flex flex-wrap gap-2">{serviceStatuses.map((s) => <button key={s} onClick={() => updateService(service.id, { status:s })} className={cx("rounded-xl px-3 py-2 text-xs", service.status === s ? "bg-white text-black" : "bg-white/10 text-white/70")}>{s}</button>)}</div>{service.folderLink && <a href={service.folderLink} target="_blank" className="mt-5 inline-flex rounded-2xl bg-white px-4 py-3 text-sm font-semibold text-black">Open Drive Folder</a>}<div className="mt-6"><div className="flex justify-between text-sm text-white/55"><span>Checklist</span><span>{pct}%</span></div><div className="mt-2 h-2 overflow-hidden rounded-full bg-white/10"><div className="h-full rounded-full bg-white" style={{width:`${pct}%`}}/></div></div><div className="mt-5 space-y-3">{service.checklist?.map((step) => <button key={step.id} onClick={() => toggleChecklist(service.id, step.id)} className={cx("flex w-full gap-3 rounded-[1.1rem] border p-4 text-left text-sm", step.done ? "border-emerald-300/25 bg-emerald-400/10" : "border-white/10 bg-white/[0.04]")}><span className={cx("grid h-6 w-6 shrink-0 place-items-center rounded-full", step.done ? "bg-emerald-300 text-black" : "bg-white/10")}>{step.done && <Check size={14}/>}</span>{step.text}</button>)}</div></div><div className="p-5"><Section title="Videos for this service" action={<Pill>{videos.length}</Pill>}/><div className="space-y-3">{videos.map((v) => <VideoCard key={v.id} video={v} services={[service]} updateVideo={updateVideo} deleteVideo={() => {}} openUpload={openUpload} openPreview={openPreview} isAdmin={false}/>)}</div></div></div></ModalShell>; }
function PreviewModal({ video, onClose }) { const url = video.fileId ? `https://drive.google.com/file/d/${video.fileId}/preview` : null; return <ModalShell onClose={onClose} title={`Preview: ${video.title}`} wide><div className="p-5">{url ? <iframe src={url} allow="autoplay" className="h-[70vh] w-full rounded-[1.4rem] border border-white/10 bg-black"/> : <Empty icon={Film} title="No preview available" body="Upload or link a Drive file first."/>}</div></ModalShell>; }
function Toast({ toast }) { const tones = { success:"border-emerald-300/25 bg-emerald-500/15 text-emerald-50", error:"border-red-300/25 bg-red-500/15 text-red-50", info:"border-sky-300/25 bg-sky-500/15 text-sky-50" }; return <motion.div initial={{opacity:0,y:24,scale:.97}} animate={{opacity:1,y:0,scale:1}} exit={{opacity:0,y:24,scale:.97}} className={cx("fixed bottom-5 right-5 z-[60] max-w-sm rounded-2xl border p-4 shadow-2xl backdrop-blur-xl", tones[toast.kind] || tones.info)}><p className="font-semibold">{toast.title}</p><p className="mt-1 text-sm opacity-80">{toast.body}</p></motion.div>; }
